import{_ as a,o as b,c as n,j as r,a as t,a1 as i}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"Cinq协会套装","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/Cinq协会套装.md","filePath":"4.资源分区/7.物品与装备/6.套装/Cinq协会套装.md"}'),p={name:"4.资源分区/7.物品与装备/6.套装/Cinq协会套装.md"};function s(o,e,d,l,_,c){return b(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"cinq协会套装",tabindex:"-1"},[t("Cinq协会套装 "),r("a",{class:"header-anchor",href:"#cinq协会套装","aria-label":'Permalink to "Cinq协会套装"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),i('<h1 id="cinq协会套装-1" tabindex="-1">Cinq协会套装 <a class="header-anchor" href="#cinq协会套装-1" aria-label="Permalink to &quot;Cinq协会套装&quot;">​</a></h1><p>Cinq协会套装</p><p>【呼吸】<br> 拥有该词条的单位在进行一次以生理属性作为关键属性的攻击前须投掷一个D10的自然骰，若出目不大于呼吸层数，则令这次攻击造成的伤害增加一半并消耗一层呼吸层数。<br> 一个单位的具有呼吸层数上限为10层。<br> 呼吸层数会在战斗结束时清空。</p><p>Cinq协会制服<br> C+1000<br> 这是一套主色调为蓝色镶嵌有白色底边的制服，内衬为黑色，肩侧纹有Cinq协会的徽章。是专门为决斗者设计的方便行动的护甲。<br> 需求：敏捷8<br> 类型：轻甲<br> 护甲防御：10/10<br> 特性：<br> 【灵巧闪避】：人物现在可以在自己回合内宣言保留一个移动动作，当人物在回合外受到攻击时，可以一个反射动作打断性的进行一次移动。<br> 若人物因此成功的脱离一次攻击的攻击范围，则人物获得1层【呼吸】。<br> 若人物因此完全躲避了一次攻击造成的伤害，则人物再获得2层【呼吸】。</p><p>Cinq协会制式迅捷剑<br> C+1000<br> Cinq协会提供给成员们使用的迅捷剑，具有非同寻常的精准性，在刺出时剑尖处会绽放出湛蓝色的圆环。只有最优秀的决斗者能充分发挥它的优点。<br> 需求：敏捷8<br> 武器类型：迅捷剑<br> 使用专业：剑<br> 武器伤害：10L<br> 特性：【轻灵】<br> 在进行单一目标的攻击时，若人物的先攻顺位高于被攻击的单位，则人物获得10点高速。<br> 人物进行单一目标的攻击命中时，若目标的闪避防御被完全破除，则该单位下一回合失去2点AP，这是一个【耗竭】效果。<br> 若人物具有【呼吸】层数，在进行单一目标的攻击时，人物可以消耗一层【呼吸】，令这次攻击具有B级先制。</p><p>决斗手套<br> D+500<br> 占据手套位<br> 具有黑色或者白色两种款式，Cinq协会成员在进行决斗时通常会将自身的手套抛向对方以宣告决斗的开启。<br> 【决斗宣告】：每场战斗一次，以花招动作将手套摘出抛向一个敌方单位，并宣言其为你这一场战斗中的决斗目标。<br> 宣言决斗目标时，你可以同时声明这场决斗的等级，这会决定这一场决斗在什么情况下结束。<br> 一级：决斗中任意一方被击落武器。<br> 二级：决斗中任意一方陷入重伤或昏迷。<br> 三级：决斗中任意一方死去。<br> 进行决斗宣告以后，本场景内人物在攻击、防御、全豁免均上获得2点洞察加值。<br> 在决斗并未结束的情况下，人物的攻击若指定除决斗目标外的其他单位，则决斗宣告带来的好处失效。<br> 在决斗并未结束的情况下，若有除人物以外的单位指定决斗目标为攻击对象，则决斗宣告带来的好处失效。<br> 特殊的，若有多个单位对同一个目标使用了决斗宣告，仅有最后指定的单位可获得决斗宣告的好处。</p><p>套装效果<br> 3件:每场影片结束时，人物在决斗宣告并未失效的情况下每赢得一场同级别的三级决斗，则决斗宣告带来的洞察加值均提升1点。一场影片中至多计算3次套装效果带来的收益。</p><p>专属专长<br> 在穿着至少两件Cinq协会装备后方可购买。<br> 价格类同通用专长。</p><p>卸力（1）<br> 每轮一次，当人物受到攻击时，若完全躲避了这次攻击造成的伤害，则人物下一轮获得4点先攻并移除2点冲击点数。</p><p>太慢了（1）<br> 一场战斗开始时，指定一个除自身外的友方单位。<br> 每轮一次，该友方单位在受到攻击时，若完全躲避了这次攻击造成的伤害，则令其下一轮获得6点先攻。</p><p>导师的指导（3）<br> 限制：一个队伍内只能有一个单位购买此专长。<br> 一场战斗开始时，指定一个除自身外的友方单位。<br> 本场景内，若该友方单位的先攻顺位高于所有敌方单位，则该单位在攻击上获得8点速度加值，在进行伤害类型为穿刺的近战攻击时加骰提升一级（至多为8加骰）。</p><p>沉睡的杀意（3）<br> 人物自身的先攻值提升2*【呼吸】层数点。<br> 若人物的先攻顺位高于所有敌方单位，则在进行伤害类型为穿刺的近战攻击时加骰提升一级（至多为8加骰）。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const h=a(p,[["render",s]]);export{C as __pageData,h as default};
